SELECT name, birth_date, updated_at
FROM political_figures
ORDER BY updated_at DESC;

SELECT name
FROM political_figures
WHERE birth_date = (SELECT MIN(birth_date) FROM political_figures);

SELECT COUNT(*) AS alive_politicians_count
FROM political_figures
WHERE death_date IS NULL;

SELECT name, birth_date
FROM political_figures
ORDER BY birth_date ASC;

SELECT figure_id, COUNT(*) AS total_tenures
FROM tenures
GROUP BY figure_id;
